import{_ as e,o as i,c as s,a2 as n}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Publicación","description":"","frontmatter":{},"headers":[],"relativePath":"es/guide/publishing.md","filePath":"es/guide/publishing.md"}'),c={name:"es/guide/publishing.md"};function o(l,a,t,r,d,p){return i(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="publicacion" tabindex="-1">Publicación <a class="header-anchor" href="#publicacion" aria-label="Permalink to &quot;Publicación&quot;">​</a></h1><p>Clearance publica tres tipos de assets vía <code>vendor:publish</code>: configuración, migraciones y traducciones. La configuración y las migraciones se gestionan automáticamente mediante el instalador (consulta <a href="/clearance-docs/es/guide/installation.html">Instalación</a>); esta página cubre cómo publicarlos manualmente, y cómo publicar las traducciones.</p><h2 id="configuracion" tabindex="-1">Configuración <a class="header-anchor" href="#configuracion" aria-label="Permalink to &quot;Configuración&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>Publica <code>config/clearance.php</code> en tu aplicación. Consulta la <a href="/clearance-docs/es/guide/configuration.html">referencia de configuración</a> para cada clave, su valor predeterminado y su propósito.</p><h2 id="traducciones" tabindex="-1">Traducciones <a class="header-anchor" href="#traducciones" aria-label="Permalink to &quot;Traducciones&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-translations</span></span></code></pre></div><p>Esto copia los 9 idiomas incluidos (<code>ar</code>, <code>en</code>, <code>es</code>, <code>fr</code>, <code>hi</code>, <code>it</code>, <code>pt</code>, <code>ru</code>, <code>zh</code>) a <code>lang/vendor/clearance/{locale}/ui.php</code> en tu app. Para añadir un nuevo idioma o sobrescribir cadenas en uno existente, añade un directorio de idioma ahí, usando <code>en/ui.php</code> como referencia canónica de claves. Todos los idiomas exponen un conjunto de claves idéntico, verificado mediante una prueba dedicada en cada cambio.</p><h2 id="sobrescribir-el-layout-del-panel" tabindex="-1">Sobrescribir el layout del panel <a class="header-anchor" href="#sobrescribir-el-layout-del-panel" aria-label="Permalink to &quot;Sobrescribir el layout del panel&quot;">​</a></h2><p>La clave de configuración <code>layout</code> controla el layout Blade usado por los componentes de página completa:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;layout&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// host app&#39;s default (config(&#39;livewire.layout&#39;))</span></span></code></pre></div><p>Déjala en <code>null</code> para usar el layout Livewire predeterminado de tu aplicación, o establécela en una vista de layout específica para renderizar el panel dentro de una estructura personalizada.</p><h2 id="migraciones" tabindex="-1">Migraciones <a class="header-anchor" href="#migraciones" aria-label="Permalink to &quot;Migraciones&quot;">​</a></h2><p>Las migraciones de Clearance se publican y ejecutan automáticamente mediante <code>php artisan clearance:install</code> - el instalador también publica y ejecuta primero las migraciones de Spatie si la tabla <code>roles</code> aún no existe. Consulta <a href="/clearance-docs/es/guide/installation.html">Instalación</a> para el flujo completo paso a paso, y el <a href="/clearance-docs/es/guide/installation.html#run-the-installer">aviso de peligro</a> sobre nunca ejecutar un <code>migrate</code> simple en una instalación nueva.</p><h2 id="relacionado" tabindex="-1">Relacionado <a class="header-anchor" href="#relacionado" aria-label="Permalink to &quot;Relacionado&quot;">​</a></h2><ul><li><a href="/clearance-docs/es/guide/configuration.html">Referencia de configuración</a> - cada clave de configuración</li><li><a href="/clearance-docs/es/guide/installation.html">Instalación</a> - el flujo completo del instalador</li><li><a href="/clearance-docs/es/guide/migration.html">Migración</a> - <code>clearance:backfill</code> para instalaciones de Spatie existentes</li></ul>`,16)])])}const g=e(c,[["render",o]]);export{u as __pageData,g as default};
